#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read integer n from input
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        // Calculate numerator: 2i + 1
        int numerator = 2 * i + 1;

        // Calculate denominator: i² - 1
        double denominator = pow(i, 2) - 1;

        // Apply alternating signs using (-1)^(i+1)
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    // Output result with precision
    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;

    // Read integer n from the user
    scanf("%d", &n);

    // Generate and print the expanding triangle pattern
    for (int i = 1; i <= n; ++i) {
        // Print leading spaces to center the digits
        for (int j = n - i; j > 0; --j) {
            printf(" ");
        }

        // Print the current row of digits
        for (int k = 0; k < i; ++k) {
            printf("%d", i);
        }

        // Move to the next line after each row
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

int main(void) {
    int numbers[NUM_NUMBERS];
    int guessed_positions[NUM_NUMBERS] = {0};
    int score = 0;
    char guess[2];

    // Generate 5 unique random numbers (1-10)
    for (int i = 0; i < NUM_NUMBERS; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }

    // Game loop
    for (int i = 0; i < NUM_NUMBERS; i++) {
        printf("Numbers: ");
        for (int j = 0; j < NUM_NUMBERS; j++) {
            if (guessed_positions[j]) {
                printf("%d ", numbers[j]);
            } else {
                printf("* ");
            }
        }
        printf("\nPick position (1-%d): ", NUM_NUMBERS);
        scanf("%d", &guessed_positions[i]);

        // Player guesses even or odd
        printf("Guess (E for even, O for odd): ");
        scanf("%s", guess);

        if ((guess[0] == 'E' && numbers[i] % 2 == 0) || 
            (guess[0] == 'O' && numbers[i] % 2 != 0)) {
            score += 5;
            printf("Correct! You win 5 points.\n");
        } else {
            printf("Incorrect. The number was: %d\n", numbers[i]);
        }

        // Reveal the number
        guessed_positions[i] = 1;
    }

    // Display final score
    printf("Final Score: %d\n", score);

    return 0;
}
